async (params, browser) => {
  // Open stock quote page
  await browser.open(`https://finance.yahoo.com/quote/${params.symbol}/`)

  // Wait for quote page to load
  await browser.waitForSelector('[data-testid=\'qsp-price\'], [class*=\'quote-header\'], h1', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load additional content
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract quote details
  const quote_data = await browser.evaluate(`const nameEl = document.querySelector('h1, [class*="quote-header"] h1, [data-testid="qsp-header"] h1'); const priceEl = document.querySelector('[data-testid="qsp-price"], [class*="price"] fin-streamer[data-field="regularMarketPrice"], fin-streamer[data-field="regularMarketPrice"]'); const changeEl = document.querySelector('[data-testid="qsp-price-change"], fin-streamer[data-field="regularMarketChange"]'); const changePctEl = document.querySelector('[data-testid="qsp-price-change-percent"], fin-streamer[data-field="regularMarketChangePercent"]'); const stats = {}; const statRows = document.querySelectorAll('[data-testid="quote-statistics"] tr, table tr, [class*="quote-stats"] li, [class*="summary-table"] tr'); statRows.forEach(function(row) { const labelEl = row.querySelector('td:first-child, span:first-child, dt'); const valueEl = row.querySelector('td:last-child, span:last-child, dd, fin-streamer'); if (labelEl && valueEl) { const label = labelEl.textContent.trim(); const value = valueEl.textContent.trim(); if (label && value && label !== value) { stats[label] = value; } } }); const marketCapEl = document.querySelector('fin-streamer[data-field="marketCap"], td[data-test="MARKET_CAP-value"]'); const volumeEl = document.querySelector('fin-streamer[data-field="regularMarketVolume"], td[data-test="TD_VOLUME-value"]'); const peRatioEl = document.querySelector('td[data-test="PE_RATIO-value"], [data-field="trailingPE"]'); const dividendEl = document.querySelector('td[data-test="DIVIDEND_AND_YIELD-value"]'); const rangeEl = document.querySelector('td[data-test="FIFTY_TWO_WK_RANGE-value"]'); return { symbol: '' + params.symbol + '', name: nameEl ? nameEl.textContent.trim() : '', price: priceEl ? priceEl.textContent.trim() : '', change: changeEl ? changeEl.textContent.trim() : '', change_percent: changePctEl ? changePctEl.textContent.trim() : '', market_cap: marketCapEl ? marketCapEl.textContent.trim() : '', volume: volumeEl ? volumeEl.textContent.trim() : '', pe_ratio: peRatioEl ? peRatioEl.textContent.trim() : '', dividend_yield: dividendEl ? dividendEl.textContent.trim() : '', fifty_two_week_range: rangeEl ? rangeEl.textContent.trim() : '', statistics: stats, url: window.location.href }`)

  return quote_data
}
